var javaMap = { string: 'String', number: 'Integer', boolean: 'Boolean', Date: 'Date', UUID: 'UUID', decimal: 'BigDecimal', date: 'Date', uuid: 'UUID' };
function javaType(t) { return javaMap[t] || pascalCase(t || ''); }
return (attributes || []).map(function (attr) {
  var t = javaType(attr.type);
  var typed = attr.multiValue ? ('List<' + t + '>') : t;
  return { camel: camelCase(attr.name), pascal: pascalCase(attr.name), type: typed };
});

return fields.map(function (f) {
  return (
    '  public ' + f.type + ' get' + f.pascal + '() {\n' +
    '  return this.' + f.camel + ';\n' +
    '  }\n\n' +
    '  public void set' + f.pascal + '(' + f.type + ' ' + f.camel + ') {\n' +
    '  this.' + f.camel + ' = ' + f.camel + ';\n' +
    '  }'
  );
}).join('\n\n');

